const root = $input.first().json;
const b = root.body && typeof root.body === 'object' ? root.body : root;
const email = (b.email || b.Email || '').trim();
const firstName = (b.firstName || b.first_name || '').trim();
const lastName = (b.lastName || b.last_name || '').trim();
const positionId = b.positionId || b.position_id;
if (!email || !firstName || !lastName || !positionId) {
  throw new Error('Missing required fields: email, firstName, lastName, positionId');
}
const emailRe = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
if (!emailRe.test(email)) throw new Error('Invalid email format');
return [{ json: {
  email,
  first_name: firstName,
  last_name: lastName,
  phone: b.phone || null,
  date_of_birth: b.dateOfBirth || b.date_of_birth || null,
  position_id: positionId,
  status: 'applied',
  application_data: {
    experience: b.experience || null,
    education: b.education || null,
    skills: b.skills || [],
    coverLetter: b.coverLetter || b.cover_letter || null
  }
} }];

const rows = $input.first().json;
const candidate = Array.isArray(rows) ? rows[0] : rows;
const appData = candidate.application_data || {};
let score = 50;
if (appData.experience) score += 15;
if (appData.education) score += 15;
if ((appData.skills || []).length > 0) score += 10;
if (appData.coverLetter || appData.cover_letter) score += 10;
score = Math.min(100, score);
const status = score >= 80 ? 'shortlisted' : 'applied';
return [{ json: {
  id: candidate.id,
  first_name: candidate.first_name,
  last_name: candidate.last_name,
  email: candidate.email,
  position_id: candidate.position_id,
  qualification_score: score,
  status
} }];

const scored = $('Calculate Score').first().json;
const updated = $input.first().json;
const row = Array.isArray(updated) ? updated[0] : updated;
return [{ json: {
  id: row.id || scored.id,
  first_name: row.first_name || scored.first_name,
  last_name: row.last_name || scored.last_name,
  email: row.email || scored.email,
  position_id: row.position_id || scored.position_id,
  qualification_score: row.qualification_score !== undefined ? row.qualification_score : scored.qualification_score,
  status: row.status || scored.status
} }];

